// Build every bidder × criterion pair as a flat list of work items.
// Each item is one unit of work: embed this criterion, search for this bidder, extract evidence.


const bidder_ids = $('Webhook Trigger').first().json.body.bidder_ids || [];
const tender_id = $('Webhook Trigger').first().json.body.tender_id;

// Criteria come back as array from FastAPI
const criteria = $input.all().map(item => item.json);

if (criteria.length === 0) {
  throw new Error('No confirmed criteria found for this tender. Officer must confirm criteria before evidence extraction.');
}

if (bidder_ids.length === 0) {
  throw new Error('No bidder_ids provided in webhook payload.');
}

const pairs = [];
for (const bidder_id of bidder_ids) {
  for (const criterion of criteria) {
    pairs.push({
      tender_id,
      bidder_id,
      criterion_id: criterion.id,
      criterion_name: criterion.name,
      criterion_type: criterion.type,
      criterion_description: criterion.description,
      threshold_value: criterion.threshold_value ?? null,
      threshold_unit: criterion.threshold_unit ?? null,
      mandatory: criterion.mandatory,
      source_section: criterion.source_section,
      // Richer embedding query: name + description + source_text together
      embedding_query: [
        criterion.name,
        criterion.description,
        criterion.source_text || ''
      ].filter(Boolean).join('. ')
    });
  }
}

// Log the matrix size for audit
console.log(`Built ${pairs.length} pairs (${bidder_ids.length} bidders × ${criteria.length} criteria)`);

return pairs.map(p => ({ json: p }));

// Attach the embedding vector back to the pair data
// The HTTP response is the embedding result; we need to merge it
// with the original pair data from the Split In Batches node

const embeddingResponse = $input.first().json;
const vector = embeddingResponse.data?.[0]?.embedding;

if (!vector || vector.length === 0) {
  throw new Error(`Embedding failed for criterion: ${embeddingResponse.criterion_id || 'unknown'}. nomic-embed-text returned no vector.`);
}

// Get the current pair from the batch
const pair = $('Split In Batches').first().json;

return [{
  json: {
    ...pair,
    vector
  }
}];

// Merge Qdrant results with the pair context and build the extraction prompt.
// If Qdrant returns empty results, we still proceed — evidence will be null.

const qdrantResponse = $input.first().json;
const searchResults = qdrantResponse.result || [];
const pair = $('Split In Batches').first().json;

// Format chunks as numbered context blocks for the LLM
const chunks = searchResults.map((r, i) => {
  const p = r.payload || {};
  const score = r.score ? ` (relevance: ${r.score.toFixed(2)})` : '';
  return `[Chunk ${i + 1}, Page ${p.page_num || '?'}${score}]\n${p.text || ''}`;
}).join('\n\n---\n\n');

const noChunksFound = searchResults.length === 0;

return [{
  json: {
    ...pair,
    context_chunks: chunks,
    chunk_count: searchResults.length,
    no_chunks_found: noChunksFound,
    // Keep raw results for source citation
    raw_search_results: searchResults.map(r => ({
      score: r.score,
      page_num: r.payload?.page_num,
      block_type: r.payload?.block_type,
      text_preview: (r.payload?.text || '').substring(0, 100)
    }))
  }
}];

// No chunks found — create a not_found EvidenceObject immediately
// without calling the LLM. Saves time and avoids hallucination risk.
const pair = $input.first().json;

return [{
  json: {
    tender_id: pair.tender_id,
    bidder_id: pair.bidder_id,
    criterion_id: pair.criterion_id,
    criterion_name: pair.criterion_name,
    value: null,
    unit: null,
    source_chunk_ref: null,
    source_page: null,
    quoted_text: null,
    confidence: 0.0,
    not_found_reason: 'No relevant document chunks found in Qdrant for this bidder. Document may not have been ingested yet, or relevant section is absent from submission.',
    extraction_method: 'qdrant_empty',
    extracted_at: new Date().toISOString()
  }
}];

// Parse the LLM evidence response into a validated EvidenceObject.
// Merge with pair metadata for the complete record.

const llmResponse = $input.first().json;
const pair = $('Split In Batches').first().json;

let raw = llmResponse.choices?.[0]?.message?.content || '';

// Strip fences
raw = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();

// Find object boundaries
const objStart = raw.indexOf('{');
const objEnd = raw.lastIndexOf('}');

if (objStart === -1 || objEnd === -1) {
  // Can't parse at all — treat as not_found
  return [{ json: {
    tender_id: pair.tender_id,
    bidder_id: pair.bidder_id,
    criterion_id: pair.criterion_id,
    criterion_name: pair.criterion_name,
    value: null,
    unit: null,
    source_chunk_ref: null,
    source_page: null,
    quoted_text: null,
    confidence: 0.0,
    not_found_reason: 'LLM response could not be parsed as JSON',
    extraction_method: 'llm_parse_failed',
    raw_response: raw.substring(0, 200),
    extracted_at: new Date().toISOString()
  }}];
}

raw = raw.substring(objStart, objEnd + 1);
// Fix trailing commas
raw = raw.replace(/,\s*([\]\}])/g, '$1');

let evidence;
try {
  evidence = JSON.parse(raw);
} catch (e) {
  evidence = {
    value: null,
    unit: null,
    source_chunk_ref: null,
    source_page: null,
    quoted_text: null,
    confidence: 0.0,
    not_found_reason: `JSON parse error: ${e.message}`
  };
}

// Normalise value: convert string numbers to float
if (typeof evidence.value === 'string') {
  const cleaned = evidence.value.replace(/[^0-9.]/g, '');
  evidence.value = cleaned ? parseFloat(cleaned) : null;
}

// Clamp confidence to [0, 1]
if (typeof evidence.confidence === 'number') {
  evidence.confidence = Math.min(1, Math.max(0, evidence.confidence));
}

return [{
  json: {
    tender_id: pair.tender_id,
    bidder_id: pair.bidder_id,
    criterion_id: pair.criterion_id,
    criterion_name: pair.criterion_name,
    criterion_type: pair.criterion_type,
    threshold_value: pair.threshold_value,
    threshold_unit: pair.threshold_unit,
    // Evidence fields from LLM
    value: evidence.value ?? null,
    unit: evidence.unit ?? null,
    source_chunk_ref: evidence.source_chunk_ref ?? null,
    source_page: evidence.source_page ?? null,
    quoted_text: evidence.quoted_text ?? null,
    confidence: evidence.confidence ?? 0.0,
    not_found_reason: evidence.not_found_reason ?? null,
    extraction_method: 'llm_mistral',
    extracted_at: new Date().toISOString()
  }
}];

// All pairs have been processed.
// Count results and check if any evidence was found at all.
const webhookData = $('Webhook Trigger').first().json.body;

return [{
  json: {
    tender_id: webhookData.tender_id,
    bidder_ids: webhookData.bidder_ids,
    status: 'evidence_extraction_complete',
    completed_at: new Date().toISOString()
  }
}];

// This node converts internal EvidenceObject → FastAPI schema

function makeId(item) {
  return `${item.tender_id}_${item.bidder_id}_${item.criterion_id}_${Date.now()}`;
}

return $input.all().map(item => {
  const e = item.json;

  return {
    json: {
      id: makeId(e),

      tender_id: e.tender_id,
      bidder_id: e.bidder_id,
      criterion_id: e.criterion_id,

      // Convert numeric → string (FastAPI expects string)
      extracted_value: e.value !== null && e.value !== undefined
        ? String(e.value)
        : null,

      // Map quoted text
      source_text: e.quoted_text || null,

      // Convert single page → array
      source_pages: e.source_page !== null && e.source_page !== undefined
        ? [e.source_page]
        : [],

      // Ensure valid confidence
      confidence: typeof e.confidence === 'number'
        ? Math.min(1, Math.max(0, e.confidence))
        : 0,

      // Default extraction method
      extraction_method: e.extraction_method || "rag",

      // Timestamp
      extracted_at: e.extracted_at || new Date().toISOString()
    }
  };
});

const pair = $input.first().json;

const systemPrompt = `You are a document evidence extractor for Indian government procurement evaluation.
Your job: find ONE specific value in the provided document chunks.

RULES (non-negotiable):
1. Return ONLY what is explicitly written in the chunks. Zero inference. Zero estimation.
2. If the value is not clearly present, return null for value.
3. quoted_text must be copied VERBATIM from the chunk — exact words, exact spelling.
4. Never calculate, derive, or average values.
5. Return ONLY a JSON object — no markdown, no fences, no explanation.
Start your response with { and end with }

Return exactly this shape:
{
  "value": 21000000,
  "unit": "INR",
  "source_chunk_ref": 2,
  "source_page": 4,
  "quoted_text": "exact words from the chunk",
  "confidence": 0.91,
  "not_found_reason": null
}

If NOT found:
{
  "value": null,
  "unit": null,
  "source_chunk_ref": null,
  "source_page": null,
  "quoted_text": null,
  "confidence": 0.0,
  "not_found_reason": "one sentence explaining why"
}`;

const userPrompt = `Criterion to find: ${pair.criterion_name}
Full requirement: ${pair.criterion_description}
Threshold: ${pair.threshold_value} ${pair.threshold_unit}

Document chunks from this bidder's submission:

${pair.context_chunks}

Find the evidence for this criterion in the chunks above. Return the JSON object only.`;

const body = {
  model: "ai/mistral:7B-Q4_0",
  temperature: 0.0,
  max_tokens: 800,
  messages: [
    { role: "system", content: systemPrompt },
    { role: "user",   content: userPrompt   }
  ]
};

return [{
  json: {
    ...pair,
    llm_body: JSON.stringify(body)
  }
}];
